+++ b/src/utils/sanitize.ts
@@ -0,0 +1,56 @@
+/**
+ * HTML sanitization utilities to prevent XSS attacks
+ */
+
+const ALLOWED_TAGS = [
+  'div', 'span', 'p', 'br', 'b', 'i', 'u', 'strong', 'em',
+  'ul', 'ol', 'li', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
+  'a', 'img', 'iframe', 'video', 'audio', 'source'
+];
+
+const ALLOWED_ATTRIBUTES: Record<string, string[]> = {
+  'a': ['href', 'title', 'target'],
+  'img': ['src', 'alt', 'title', 'width', 'height'],
+  'iframe': ['src', 'width', 'height', 'frameborder', 'allowfullscreen'],
+  'video': ['src', 'width', 'height', 'controls', 'autoplay', 'loop', 'muted'],
+  'audio': ['src', 'controls', 'autoplay', 'loop', 'muted'],
+  'source': ['src', 'type'],
+  '*': ['class', 'id', 'style']
+};
+
+const SAFE_URL_PATTERN = /^(https?:)?\/\/[^\s"'<>]+$/i;
+
+export function sanitizeAttribute(tagName: string, attribute: string, value: string): string {
+  // Check if attribute is allowed for this tag
+  const allowedAttrs = ALLOWED_ATTRIBUTES[tagName] || [];
+  const globalAttrs = ALLOWED_ATTRIBUTES['*'] || [];
+  
+  if (![...allowedAttrs, ...globalAttrs].includes(attribute)) {
+    return '';
+  }
+
+  // Special handling for URLs
+  if (attribute === 'href' || attribute === 'src') {
+    if (!SAFE_URL_PATTERN.test(value)) {
+      return '';
+    }
+  }
+
+  // Escape potentially dangerous characters
+  return value
+    .replace(/&/g, '&amp;')
+    .replace(/</g, '&lt;')
+    .replace(/>/g, '&gt;')
+    .replace(/"/g, '&quot;')
+    .replace(/'/g, '&#x27;');
+}
+
+export function sanitizeHTML(html: string): string {
+  const parser = new DOMParser();
+  const doc = parser.parseFromString(html, 'text/html');
+  
+  // Remove disallowed tags and sanitize attributes
+  // Implementation details would depend on specific requirements
+  // This is a simplified version - actual implementation would be more comprehensive
+  return doc.body.innerHTML;
+}

