@@ -0,0 +1,49 @@
+/**
+ * Convert filter string to safe Knex format
+ * Prevents SQL injection by validating and sanitizing filter input
+ */
+function filterToKnex(filter) {
+    if (!filter || typeof filter !== 'string') {
+        return filter;
+    }
+
+    // Remove any SQL injection attempts
+    const dangerousPatterns = [
+        /(\b(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|EXEC|ALTER|CREATE|TRUNCATE)\b)/gi,
+        /(\b(OR|AND)\s+['"]?\d+['"]?\s*[=<>]+\s*['"]?\d+['"]?)/gi,
+        /(--|\/\*|\*\/|;)/g,
+        /(\b(TRUE|FALSE|NULL)\b)/gi
+    ];
+
+    let safeFilter = filter;
+    dangerousPatterns.forEach(pattern => {
+        safeFilter = safeFilter.replace(pattern, '');
+    });
+
+    // Validate filter format - only allow alphanumeric, spaces, and basic operators
+    const validFilterRegex = /^[a-zA-Z0-9_\s\.=<>!%&|\(\)\-]+$/;
+    
+    if (!validFilterRegex.test(safeFilter)) {
+        throw new Error('Invalid filter format');
+    }
+
+    // Ensure filter uses parameterized format
+    const parts = safeFilter.split(/\s+(AND|OR)\s+/gi);
+    const safeParts = [];
+    
+    for (let i = 0; i < parts.length; i++) {
+        const part = parts[i].trim();
+        if (['AND', 'OR'].includes(part.toUpperCase())) {
+            safeParts.push(part.toUpperCase());
+        } else if (part.includes('=') || part.includes('>') || part.includes('<') || part.includes('!=')) {
+            // This is a condition - ensure it doesn't contain raw values
+            const [column, ...valueParts] = part.split(/[=<>!]+/);
+            if (column && valueParts.length > 0) {
+                safeParts.push(`${column.trim()} ?`);
+            }
+        }
+    }
+    
+    return safeParts.join(' ');
+}
+module.exports = filterToKnex;

