+package org.apache.streampipes.extensions.management.util;
+
+import java.net.InetAddress;
+import java.net.MalformedURLException;
+import java.net.URL;
+import java.net.UnknownHostException;
+import java.util.Arrays;
+import java.util.HashSet;
+import java.util.Set;
+
+public class UrlValidator {
+  
+  private static final Set<String> ALLOWED_SCHEMES = new HashSet<>(Arrays.asList("http", "https"));
+  private static final Set<String> BLOCKED_HOSTS = new HashSet<>(Arrays.asList(
+      "localhost", "127.0.0.1", "::1", "0.0.0.0"
+  ));
+  
+  public static void validateUrl(String urlString) throws MalformedURLException {
+    URL url = new URL(urlString);
+    
+    // Validate scheme
+    String scheme = url.getProtocol();
+    if (!ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
+      throw new MalformedURLException("Invalid URL scheme: " + scheme);
+    }
+    
+    // Validate host
+    String host = url.getHost();
+    if (BLOCKED_HOSTS.contains(host.toLowerCase())) {
+      throw new MalformedURLException("Access to localhost/loopback addresses is not allowed");
+    }
+    
+    // Check for private/internal IP addresses
+    try {
+      InetAddress address = InetAddress.getByName(host);
+      if (address.isSiteLocalAddress() || address.isLoopbackAddress() 
+          || address.isAnyLocalAddress() || address.isLinkLocalAddress()) {
+        throw new MalformedURLException("Access to private/internal networks is not allowed");
+      }
+    } catch (UnknownHostException e) {
+      // If we can't resolve the host, we'll let it pass but log a warning
+    }
+  }
+}

